const SESSION_ID = 'YOUR_SESSION_ID';
const MY_PHONE = 'YOUR_PHONE';

const body = $input.first().json.body || $input.first().json;

if (body.challenge) {
  return [{ json: { challenge: body.challenge } }];
}

const event = body.event || body;
const text = event.text || event.message || '';
const user = event.user_name || event.user || 'Someone';
const channel = event.channel_name || event.channel || 'a channel';

if (!text) {
  return [{ json: { skip: true, reason: 'Empty message' } }];
}

const message = `*Slack — #${channel}*\n${user}: ${text}`;

return [{
  json: {
    session_id: SESSION_ID,
    chat_id: MY_PHONE + '@c.us',
    message: message,
    channel: channel,
    sender: user,
    skip: false
  }
}];
